   597→    // Digits is the number of digits in the TOTP code.
   598→    uint32 Digits = 5;
   599→    // Account is the account name for this user.
   600→    string Account = 6;
   601→}
   602→
   603→// TOTPRegisterResponse is a response to TOTPRegisterChallenge.
   604→message TOTPRegisterResponse { string Code = 1; }
   605→
   606→// AddMFADeviceRequest is a message sent by the client during AddMFADevice RPC.
   607→message AddMFADeviceRequest {
   608→    oneof Request {
   609→        // Init describes the new device.
   610→        AddMFADeviceRequestInit Init = 1;
   611→        // ExistingMFAResponse is a response to ExistingMFAChallenge auth
   612→        // challenge.
   613→        MFAAuthenticateResponse ExistingMFAResponse = 2;
   614→        // NewMFARegisterResponse is a response to NewMFARegisterChallenge
   615→        // registration challenge.
   616→        MFARegisterResponse NewMFARegisterResponse = 3;
   617→    }
   618→}
   619→
   620→// AddMFADeviceResponse is a message sent by the server during AddMFADevice
   621→// RPC.
   622→message AddMFADeviceResponse {
   623→    oneof Response {
   624→        // ExistingMFAChallenge is an auth challenge using an existing MFA
   625→        // device.
   626→        MFAAuthenticateChallenge ExistingMFAChallenge = 1;
   627→        // NewMFARegisterChallenge is a registration challenge for a new MFA
   628→        // device.
   629→        MFARegisterChallenge NewMFARegisterChallenge = 2;
   630→        // Ack is a confirmation of successful device registration.
   631→        AddMFADeviceResponseAck Ack = 3;
   632→    }
   633→}
   634→
   635→// AddMFADeviceRequestInit describes the new MFA device.
   636→message AddMFADeviceRequestInit {
   637→    string DeviceName = 1;
   638→    enum DeviceType {
   639→        TOTP = 0;
   640→        U2F = 1;
   641→    }
   642→    DeviceType Type = 2;
   643→}
   644→
   645→// AddMFADeviceResponseAck is a confirmation of successful device registration.
   646→message AddMFADeviceResponseAck { types.MFADevice Device = 1; }
   647→
   648→// DeleteMFADeviceRequest is a message sent by the client during
   649→// DeleteMFADevice RPC.
   650→message DeleteMFADeviceRequest {
   651→    oneof Request {
   652→        // Init describes the device to be deleted.
   653→        DeleteMFADeviceRequestInit Init = 1;
   654→        // MFAResponse is a response to MFAChallenge auth challenge.
   655→        MFAAuthenticateResponse MFAResponse = 2;
   656→    }
   657→}
   658→
   659→message DeleteMFADeviceResponse {
   660→    oneof Response {
   661→        // MFAChallenge is an auth challenge using any existing MFA device.
   662→        MFAAuthenticateChallenge MFAChallenge = 1;
   663→        // Ack is a confirmation of successful device deletion.
   664→        DeleteMFADeviceResponseAck Ack = 2;
   665→    }
   666→}
   667→
   668→// DeleteMFADeviceRequestInit describes the device to be deleted.
   669→message DeleteMFADeviceRequestInit {
   670→    // DeviceName is an MFA device name or ID to be deleted.
   671→    string DeviceName = 1;
   672→}
   673→
   674→// DeleteMFADeviceResponseAck is a confirmation of successful device deletion.
   675→message DeleteMFADeviceResponseAck {}
   676→
   677→// GetMFADeviceRequest is a request for MFA devices for the calling user.
   678→message GetMFADevicesRequest {}
   679→
   680→// GetMFADeviceResponse is a response for GetMFADevices RPC.
   681→message GetMFADevicesResponse { repeated types.MFADevice Devices = 1; }
   682→
   683→// AuthService is authentication/authorization service implementation
   684→service AuthService {
   685→    // SendKeepAlives allows node to send a stream of keep alive requests
   686→    rpc SendKeepAlives(stream types.KeepAlive) returns (google.protobuf.Empty);
   687→    // WatchEvents returns a new stream of cluster events
   688→    rpc WatchEvents(Watch) returns (stream Event);
   689→    // UpsertNode upserts node
   690→    rpc UpsertNode(types.ServerV2) returns (types.KeepAlive);
   691→    // GenerateUserCerts generates a set of user certificates for use by `tctl
   692→    // auth sign`.
   693→    rpc GenerateUserCerts(UserCertsRequest) returns (Certs);
   694→    // GetUser gets a user resource by name.
   695→    rpc GetUser(GetUserRequest) returns (types.UserV2);
   696→    // GetUsers gets all current user resources.
   697→    rpc GetUsers(GetUsersRequest) returns (stream types.UserV2);
   698→    // GetAccessRequests gets all pending access requests.
   699→    rpc GetAccessRequests(types.AccessRequestFilter) returns (AccessRequests);
   700→    // CreateAccessRequest creates a new access request.
   701→    rpc CreateAccessRequest(types.AccessRequestV3) returns (google.protobuf.Empty);
   702→    // DeleteAccessRequest deletes an access request.
   703→    rpc DeleteAccessRequest(RequestID) returns (google.protobuf.Empty);
   704→    // SetAccessRequestState sets the state of an access request.
   705→    rpc SetAccessRequestState(RequestStateSetter) returns (google.protobuf.Empty);
   706→    // GetAccessCapabilities requests the access capabilites of a user.
   707→    rpc GetAccessCapabilities(types.AccessCapabilitiesRequest) returns (types.AccessCapabilities);
   708→
   709→    // GetPluginData gets all plugin data matching the supplied filter.
   710→    rpc GetPluginData(types.PluginDataFilter) returns (PluginDataSeq);
   711→    // UpdatePluginData updates a plugin's resource-specific datastore.
   712→    rpc UpdatePluginData(types.PluginDataUpdateParams) returns (google.protobuf.Empty);
   713→    // Ping gets basic info about the auth server. This method is intended
   714→    // to mimic the behavior of the proxy's Ping method, and may be used by
   715→    // clients for verification or configuration on startup.
   716→    rpc Ping(PingRequest) returns (PingResponse);
   717→    // RotateResetPasswordTokenSecrets rotates token secrets for a given tokenID.
   718→    rpc RotateResetPasswordTokenSecrets(RotateResetPasswordTokenSecretsRequest)
   719→        returns (types.ResetPasswordTokenSecretsV3);
   720→    // GetResetPasswordToken returns a token.
   721→    rpc GetResetPasswordToken(GetResetPasswordTokenRequest) returns (types.ResetPasswordTokenV3);
   722→    // CreateResetPasswordToken creates ResetPasswordToken.
   723→    rpc CreateResetPasswordToken(CreateResetPasswordTokenRequest)
   724→        returns (types.ResetPasswordTokenV3);
   725→    // CreateUser inserts a new user entry to a backend.
   726→    rpc CreateUser(types.UserV2) returns (google.protobuf.Empty);
   727→    // UpdateUser updates an existing user in a backend.
   728→    rpc UpdateUser(types.UserV2) returns (google.protobuf.Empty);
   729→    // DeleteUser deletes an existing user in a backend by username.
   730→    rpc DeleteUser(DeleteUserRequest) returns (google.protobuf.Empty);
   731→
   732→    // AcquireSemaphore acquires lease with requested resources from semaphore.
   733→    rpc AcquireSemaphore(types.AcquireSemaphoreRequest) returns (types.SemaphoreLease);
   734→    // KeepAliveSemaphoreLease updates semaphore lease.
   735→    rpc KeepAliveSemaphoreLease(types.SemaphoreLease) returns (google.protobuf.Empty);
   736→    // CancelSemaphoreLease cancels semaphore lease early.
   737→    rpc CancelSemaphoreLease(types.SemaphoreLease) returns (google.protobuf.Empty);
   738→    // GetSemaphores returns a list of all semaphores matching the supplied filter.
   739→    rpc GetSemaphores(types.SemaphoreFilter) returns (Semaphores);
   740→    // DeleteSemaphore deletes a semaphore matching the supplied filter.
   741→    rpc DeleteSemaphore(types.SemaphoreFilter) returns (google.protobuf.Empty);
   742→
   743→    // EmitAuditEvent emits audit event
   744→    rpc EmitAuditEvent(events.OneOf) returns (google.protobuf.Empty);
   745→    // CreateAuditStream creates or resumes audit events streams
   746→    rpc CreateAuditStream(stream AuditStreamRequest) returns (stream events.StreamStatus);
   747→
   748→    // GetAppServers gets all application servers.
   749→    rpc GetAppServers(GetAppServersRequest) returns (GetAppServersResponse);
   750→    // UpsertAppServer adds an application server.
   751→    rpc UpsertAppServer(UpsertAppServerRequest) returns (types.KeepAlive);
   752→    // DeleteAppServer removes an application server.
   753→    rpc DeleteAppServer(DeleteAppServerRequest) returns (google.protobuf.Empty);
   754→    // DeleteAllAppServers removes all application servers.
   755→    rpc DeleteAllAppServers(DeleteAllAppServersRequest) returns (google.protobuf.Empty);
   756→
   757→    // GenerateAppToken will generate a JWT token for application access.
   758→    rpc GenerateAppToken(GenerateAppTokenRequest) returns (GenerateAppTokenResponse);
   759→
   760→    // GetAppSession gets an application web session.
   761→    rpc GetAppSession(GetAppSessionRequest) returns (GetAppSessionResponse);
   762→    // GetAppSessions gets all application web sessions.
   763→    rpc GetAppSessions(google.protobuf.Empty) returns (GetAppSessionsResponse);
   764→    // CreateAppSession creates an application web session. Application web
   765→    // sessions represent a browser session the client holds.
   766→    rpc CreateAppSession(CreateAppSessionRequest) returns (CreateAppSessionResponse);
   767→    // DeleteAppSession removes an application web session.
   768→    rpc DeleteAppSession(DeleteAppSessionRequest) returns (google.protobuf.Empty);
   769→    // DeleteAllAppSessions removes all application web sessions.
   770→    rpc DeleteAllAppSessions(google.protobuf.Empty) returns (google.protobuf.Empty);
   771→
   772→    // GetWebSession gets a web session.
   773→    rpc GetWebSession(types.GetWebSessionRequest) returns (GetWebSessionResponse);
   774→    // GetWebSessions gets all web sessions.
   775→    rpc GetWebSessions(google.protobuf.Empty) returns (GetWebSessionsResponse);
   776→    // DeleteWebSession deletes a web session.
   777→    rpc DeleteWebSession(types.DeleteWebSessionRequest) returns (google.protobuf.Empty);
   778→    // DeleteAllWebSessions deletes all web sessions.
   779→    rpc DeleteAllWebSessions(google.protobuf.Empty) returns (google.protobuf.Empty);
   780→
   781→    // GetWebToken gets a web token.
   782→    rpc GetWebToken(types.GetWebTokenRequest) returns (GetWebTokenResponse);
   783→    // GetWebTokens gets all web tokens.
   784→    rpc GetWebTokens(google.protobuf.Empty) returns (GetWebTokensResponse);
   785→    // DeleteWebToken deletes a web token.
   786→    rpc DeleteWebToken(types.DeleteWebTokenRequest) returns (google.protobuf.Empty);
   787→    // DeleteAllWebTokens deletes all web tokens.
   788→    rpc DeleteAllWebTokens(google.protobuf.Empty) returns (google.protobuf.Empty);
   789→
   790→    // UpdateRemoteCluster updates remote cluster
   791→    rpc UpdateRemoteCluster(types.RemoteClusterV3) returns (google.protobuf.Empty);
   792→
   793→    // GetKubeServices gets all kubernetes services.
   794→    rpc GetKubeServices(GetKubeServicesRequest) returns (GetKubeServicesResponse);
   795→    // UpsertKubeService adds or updates a kubernetes service.
   796→    rpc UpsertKubeService(UpsertKubeServiceRequest) returns (google.protobuf.Empty);
   797→    // DeleteKubeService removes a kubernetes service.
   798→    rpc DeleteKubeService(DeleteKubeServiceRequest) returns (google.protobuf.Empty);
   799→    // DeleteAllKubeServices removes all kubernetes services.
   800→    rpc DeleteAllKubeServices(DeleteAllKubeServicesRequest) returns (google.protobuf.Empty);
   801→
   802→    // GetDatabaseServers returns all registered database proxy servers.
   803→    rpc GetDatabaseServers(GetDatabaseServersRequest) returns (GetDatabaseServersResponse);
   804→    // UpsertDatabaseServer registers a new database proxy server.
   805→    rpc UpsertDatabaseServer(UpsertDatabaseServerRequest) returns (types.KeepAlive);
   806→    // DeleteDatabaseServer removes the specified database proxy server.
   807→    rpc DeleteDatabaseServer(DeleteDatabaseServerRequest) returns (google.protobuf.Empty);
   808→    // DeleteAllDatabaseServers removes all registered database proxy servers.
   809→    rpc DeleteAllDatabaseServers(DeleteAllDatabaseServersRequest) returns (google.protobuf.Empty);
   810→
   811→    // SignDatabaseCSR generates client certificate used by proxy to
   812→    // authenticate with a remote database service.
   813→    rpc SignDatabaseCSR(DatabaseCSRRequest) returns (DatabaseCSRResponse);
   814→    // GenerateDatabaseCert generates client certificate used by a database
   815→    // service to authenticate with the database instance.
   816→    rpc GenerateDatabaseCert(DatabaseCertRequest) returns (DatabaseCertResponse);
   817→
   818→    // AddMFADevice adds an MFA device for the user calling this RPC.
   819→    //
   820→    // The RPC is streaming both ways and the message sequence is:
   821→    // (-> means client-to-server, <- means server-to-client)
   822→    // -> Init
   823→    // <- ExistingMFAChallenge
   824→    // -> ExistingMFAResponse
   825→    // <- NewMFARegisterChallenge
   826→    // -> NewMFARegisterResponse
   827→    // <- Ack
   828→    rpc AddMFADevice(stream AddMFADeviceRequest) returns (stream AddMFADeviceResponse);
   829→    // DeleteMFADevice deletes an MFA device for the user calling this RPC.
   830→    //
   831→    // The RPC is streaming both ways and the message sequence is:
   832→    // (-> means client-to-server, <- means server-to-client)
   833→    // -> Init
   834→    // <- MFAChallenge
   835→    // -> MFAResponse
   836→    // <- Ack
   837→    rpc DeleteMFADevice(stream DeleteMFADeviceRequest) returns (stream DeleteMFADeviceResponse);
   838→    // GetMFADevices returns all MFA devices registered for the user calling
   839→    // this RPC.
   840→    rpc GetMFADevices(GetMFADevicesRequest) returns (GetMFADevicesResponse);
   841→}
   842→

