   567→// MFARegisterResponse is a response to MFARegisterChallenge.
   568→message MFARegisterResponse {
   569→    oneof Response {
   570→        U2FRegisterResponse U2F = 1;
   571→        TOTPRegisterResponse TOTP = 2;
   572→    }
   573→}
   574→
   575→// U2FRegisterChallenge is a challenge for registering a new U2F device.
   576→message U2FRegisterChallenge {
   577→    string Challenge = 1;
   578→    string AppID = 2;
   579→}
   580→
   581→// U2FRegisterResponse is a response to U2FRegisterChallenge.
   582→message U2FRegisterResponse {
   583→    string RegistrationData = 1;
   584→    string ClientData = 2;
   585→}
   586→
   587→// TOTPRegisterChallenge is a challenge for registering a new TOTP device.
   588→message TOTPRegisterChallenge {
   589→    // Secret is a secret shared by client and server to generate codes.
   590→    string Secret = 1;
   591→    // Issuer is the name of the Teleport cluster.
   592→    string Issuer = 2;
   593→    // PeriodSeconds is a period for TOTP code rotation, in seconds.
   594→    uint32 PeriodSeconds = 3;
   595→    // Algorithm is the TOTP hashing algorithm.
   596→    string Algorithm = 4;
   597→    // Digits is the number of digits in the TOTP code.
   598→    uint32 Digits = 5;
   599→    // Account is the account name for this user.
   600→    string Account = 6;
   601→}
   602→
   603→// TOTPRegisterResponse is a response to TOTPRegisterChallenge.
   604→message TOTPRegisterResponse { string Code = 1; }
   605→
   606→// AddMFADeviceRequest is a message sent by the client during AddMFADevice RPC.
   607→message AddMFADeviceRequest {
   608→    oneof Request {
   609→        // Init describes the new device.
   610→        AddMFADeviceRequestInit Init = 1;
   611→        // ExistingMFAResponse is a response to ExistingMFAChallenge auth
   612→        // challenge.
   613→        MFAAuthenticateResponse ExistingMFAResponse = 2;
   614→        // NewMFARegisterResponse is a response to NewMFARegisterChallenge
   615→        // registration challenge.
   616→        MFARegisterResponse NewMFARegisterResponse = 3;
   617→    }
   618→}
